#include <math.h>
#include <stdio.h>

int main() {
	long long xa, ya, xb, yb, xc, yc;

	scanf("%lld%lld%lld%lld%lld%lld", &xa, &ya, &xb, &yb, &xc, &yc);
	printf((xa - xb) * (xa - xb) + (ya - yb) * (ya - yb) == (xc - xb) * (xc - xb) + (yc - yb) * (yc - yb) && (xb - xa) * (yc - yb) != (yb - ya) * (xc - xb) ? "Yes\n" : "No\n");
	return 0;
}

